import{_ as t,o as e,c as o,a2 as r}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"行动顺序表","description":"","frontmatter":{},"headers":[],"relativePath":"guide/action-queue.md","filePath":"guide/action-queue.md","lastUpdated":1781102744000}'),i={name:"guide/action-queue.md"};function s(d,a,l,n,h,c){return e(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="行动顺序表" tabindex="-1">行动顺序表 <a class="header-anchor" href="#行动顺序表" aria-label="Permalink to &quot;行动顺序表&quot;">​</a></h1><p>行动顺序表是一个队列，决定角色的行动顺序。</p><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><ol><li>顺序表是一个<strong>队列</strong>，队首先行，依次行动</li><li>顺序表允许<strong>插队</strong>：当角色的硬直时间小于先前角色即可插队；硬直时间相同时，插入到先前角色后方</li></ol><h2 id="排位顺序" tabindex="-1">排位顺序 <a class="header-anchor" href="#排位顺序" aria-label="Permalink to &quot;排位顺序&quot;">​</a></h2><p>游戏开始时，按以下规则排位：</p><p><strong>行动速度较快的角色先进入顺序表。</strong></p><p>示例：4 名角色速度相同，通过多次随机抽取决定顺序。</p><h2 id="运行时" tabindex="-1">运行时 <a class="header-anchor" href="#运行时" aria-label="Permalink to &quot;运行时&quot;">​</a></h2><p>排位确定后 → 时间开始流逝 → 队首角色开始行动 → 行动后计算硬直时间并重新加入顺序表。</p><h3 id="硬直时间计算公式" tabindex="-1">硬直时间计算公式 <a class="header-anchor" href="#硬直时间计算公式" aria-label="Permalink to &quot;硬直时间计算公式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>实际硬直时间 = 硬直时间 × (1 - 行动系数)</span></span></code></pre></div><h3 id="行动系数" tabindex="-1">行动系数 <a class="header-anchor" href="#行动系数" aria-label="Permalink to &quot;行动系数&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>行动系数 = 行动速度 / 1500 × 100%</span></span></code></pre></div><p>保留两位小数。行动系数上限为 <strong>90%</strong>（行动速度达到 1350 时）。</p><div class="tip custom-block"><p class="custom-block-title">示例</p><p>290 速度 → 行动系数 = 290/1500 = 19.33% 硬直时间为 5 → 实际硬直时间 = 5 × (1 - 19.33%) = <strong>4.03</strong></p></div><h3 id="硬直补偿" tabindex="-1">硬直补偿 <a class="header-anchor" href="#硬直补偿" aria-label="Permalink to &quot;硬直补偿&quot;">​</a></h3><p>被连续插队 <code>当前队列角色数</code> 次（至少 5 次）的角色，获得行动保护：下次行动前无法被其他角色插队。</p><blockquote><p>回合外爆发技插队不计入硬直补偿。该功能默认开启，可关闭。</p></blockquote><h2 id="插队机制" tabindex="-1">插队机制 <a class="header-anchor" href="#插队机制" aria-label="Permalink to &quot;插队机制&quot;">​</a></h2><p>当角色的硬直时间小于先前角色即可插队。</p><h3 id="特殊-预释放爆发技插队" tabindex="-1">特殊：预释放爆发技插队 <a class="header-anchor" href="#特殊-预释放爆发技插队" aria-label="Permalink to &quot;特殊：预释放爆发技插队&quot;">​</a></h3><p>角色在回合外使用预释放爆发技：</p><ul><li>立即获得 <strong>0</strong> 个时间单位的硬直时间进入顺序表</li><li>下次行动前<strong>无法被其他角色插队</strong></li><li>多个预释放爆发技：跟在先前预释放爆发技角色之后插入，硬直时间额外 +0.01</li></ul><h2 id="例外情况-硬直时间不受行动系数减免" tabindex="-1">例外情况（硬直时间不受行动系数减免） <a class="header-anchor" href="#例外情况-硬直时间不受行动系数减免" aria-label="Permalink to &quot;例外情况（硬直时间不受行动系数减免）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>硬直时间</th></tr></thead><tbody><tr><td>完全行动不能状态下结束回合</td><td>7</td></tr><tr><td>战斗不能/行动受限 + 未行动/纯移动</td><td>5</td></tr><tr><td>常态下未行动/纯移动</td><td>3</td></tr><tr><td>吟唱态结算失败</td><td>3</td></tr><tr><td>复活后</td><td>5</td></tr></tbody></table>',26)])])}const b=t(i,[["render",s]]);export{u as __pageData,b as default};
